sys_script_include.script:
var SelectSubordinateUsers = Class.create();
SelectSubordinateUsers.prototype = Object.extendsObject(AbstractAjaxProcessor, {
    loadSubordinates: function(managerID) {

		var subordinates = '';

		if (managerID == null){
			subordinates += this.getParameter('sysparm_managerID');
		} else {
			subordinates += managerID;
		}

        //var subordinates = this.getParameter('sysparm_managerID');
        var gr = new GlideRecord("sys_user");
        gr.addQuery("manager", managerID);
		gr.addQuery("active", true);
        gr.query();

        while (gr.next()) {
            subordinates += ',' + gr.sys_id;
        }

        return 'active=true^sys_idIN' + subordinates;
    },

    type: 'SelectSubordinateUsers'
});
